/** Normalize various locale codes (e.g., 'en-US', 'zh-Hans') to our 2-letter base. */
export function normalizeLocale(input: string | undefined | null): Locale {
  if (!input) return "en";
  const lower = input.toLowerCase();
  if (lower.startsWith("ja")) return "ja";
  if (lower.startsWith("zh")) return "zh";
  if (lower.startsWith("de")) return "de";
  if (lower.startsWith("fr")) return "fr";
  if (lower.startsWith("es")) return "es";
  if (lower.startsWith("ko")) return "ko";
  if (lower.startsWith("it")) return "it";
  if (lower.startsWith("pt")) return "pt";
  if (lower.startsWith("tr")) return "tr";
  return "en";
}

/** Look up a localized string with optional {{var}} interpolation. */
export function t(key: string, locale: string | undefined | null = 'en', vars: Record<string, string | number> = {}): string {
  const localeKey = normalizeLocale(locale);
  const entry = STRINGS[key];
  if (!entry) return key;
  let str = entry[localeKey] ?? entry.en ?? key;
  for (const [k, v] of Object.entries(vars)) {
    str = str.replace(new RegExp(`\\{\\{${k}\\}\\}`, 'g'), String(v));
  }
  return str;
}
